import React, { useEffect, useState } from 'react';


const base64Logo = `data:image/jpeg;base64,`;

const NetworkStatusOverlay: React.FC = () => {
  const [online, setOnline] = useState<boolean>(navigator.onLine);
  const [dotCount, setDotCount] = useState(2);

  useEffect(() => {
    const handleOnline = () => {
      setOnline(true);
      window.location.reload();
    };
    const handleOffline = () => {
      setOnline(false);
      console.warn('Network connection lost.');
    };

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const dotInterval = setInterval(() => {
      setDotCount((count) => (count >= 3 ? 0 : count + 1));
    }, 1000);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      clearInterval(dotInterval);
    };
  }, []);

  useEffect(() => {
    if (!online) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => {
      document.body.style.overflow = '';
    };
  }, [online]);

  if (online) return null;

  return (
    <div
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundImage: `url(${base64Logo})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        zIndex: 9999,
      }}
    >
      <div
        style={{
          position: 'absolute',
          top: '5%',
          width: '100%',
          textAlign: 'center',
          fontSize: '1.5rem',
          color: '#fff',
          fontFamily: 'sans-serif',
          textShadow: '0 0 5px rgba(0,0,0,0.7)',
          userSelect: 'none',
       }}
      >
        Reconnecting
        <span
          style={{
            display: 'inline-block',
            width: '1.5em', // enough for 3 dots
            textAlign: 'left',
          }}
        >
          {'.'.repeat(dotCount)}
        </span>
      </div>
    </div>
  );
};

export default NetworkStatusOverlay;
